   144→
   145→export function subscribeToUpdates(onUpdate: () => void): () => void {
   146→  let ws: WebSocket | null = null;
   147→  let timer: ReturnType<typeof setTimeout> | null = null;
   148→  let closed = false;
   149→  let delay = 1000;
   150→
   151→  function connect() {
   152→    if (closed) return;
   153→    ws = new WebSocket(WS_URL);
   154→
   155→    ws.onopen = () => {
   156→      delay = 1000; // reset backoff on successful connection
   157→    };
   158→
   159→    ws.onmessage = (e) => {
   160→      try {
   161→        const msg = JSON.parse(e.data as string) as { type: string };
   162→        if (msg.type === "sessions_updated") onUpdate();
   163→      } catch {
   164→        // ignore malformed messages
   165→      }
   166→    };
   167→
   168→    ws.onclose = () => {
   169→      if (closed) return;
   170→      timer = setTimeout(() => {
   171→        delay = Math.min(delay * 2, 30000);
