   193→      </View>
   194→    );
   195→  }
   196→
   197→  if (error) {
   198→    return (
   199→      <View style={s.centered}>
   200→        <Text style={s.errorText}>{error}</Text>
   201→      </View>
   202→    );
   203→  }
   204→
   205→  if (nodes.length === 0) {
   206→    return (
   207→      <View style={s.centered}>
   208→        <Text style={s.emptyText}>No sessions yet.</Text>
   209→      </View>
   210→    );
   211→  }
   212→
   213→  return (
   214→    <View style={[s.scroll, { height: contentHeight }]}>
   215→      {nodes.map((node, i) => {
   216→        const isExpanded = expanded.has(node.session.sessionId);
   217→        return (
   218→          <View key={node.session.sessionId}>
   219→            {/* Vertical connector line running down from parent */}
   220→            {node.depth > 0 && (
   221→              <View
   222→                style={[
   223→                  s.connector,
   224→                  { left: 12 + (node.depth - 1) * INDENT + 9 },
   225→                ]}
   226→              />
   227→            )}
   228→            <TreeNode
   229→              node={node}
   230→              isExpanded={isExpanded}
   231→              onPress={() =>
   232→                navigation.push("SessionDetail", {
   233→                  sessionId: node.session.sessionId,
   234→                  title: node.session.summary ?? node.session.sessionId.slice(0, 8) + "…",
   235→                })
   236→              }
   237→              onToggle={() => toggle(node.session.sessionId)}
   238→            />
   239→          </View>
   240→        );
   241→      })}
   242→    </View>
   243→  );
   244→}
   245→
   246→const s = StyleSheet.create({
   247→  scroll: {
