   253→    alignItems: "center",
   254→    justifyContent: "center",
   255→    padding: 24,
   256→  },
   257→  loadingText: { fontSize: 14, color: "#9ca3af" },
   258→  errorText:   { fontSize: 14, color: "#ef4444", textAlign: "center" },
   259→  emptyText:   { fontSize: 14, color: "#9ca3af" },
   260→
   261→  row: {
