import React, { useCallback, useEffect, useState } from "react";
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  useWindowDimensions,
} from "react-native";
import { Stack, useRouter } from "expo-router";
import { useHeaderHeight } from "@react-navigation/elements";
import { fetchCheckpoints, subscribeToUpdates, type Checkpoint } from "../api";

// ─── Column config ────────────────────────────────────────────────────────────

const COL = {
  id:       130,
  branch:   140,
  intent:   300,
  sessions:  70,
  files:     70,
  tokens:    90,
} as const;

const TOTAL_WIDTH = Object.values(COL).reduce((a, b) => a + b, 0) + 16;

const COLUMNS: { label: string; width: number }[] = [
  { label: "Checkpoint", width: COL.id },
  { label: "Branch",     width: COL.branch },
  { label: "Intent",     width: COL.intent },
  { label: "Sessions",   width: COL.sessions },
  { label: "Files",      width: COL.files },
  { label: "Out tokens", width: COL.tokens },
];

// ─── Row component ────────────────────────────────────────────────────────────

function CheckpointRow({ checkpoint, onPress }: { checkpoint: Checkpoint; onPress: () => void }) {
  const outTokens = checkpoint.tokenUsage?.outputTokens ?? 0;
  return (
    <TouchableOpacity onPress={onPress} style={s.row}>
      <Text style={[s.cell, s.idCell, { width: COL.id }]} numberOfLines={1}>
        {checkpoint.checkpointId}
      </Text>
      <Text style={[s.cell, s.cellText, { width: COL.branch }]} numberOfLines={1}>
        {checkpoint.branch ?? "—"}
      </Text>
      <Text style={[s.cell, s.intentCell, { width: COL.intent }]} numberOfLines={1}>
        {checkpoint.summary?.intent ?? "—"}
      </Text>
      <Text style={[s.cell, s.numCell, { width: COL.sessions }]} numberOfLines={1}>
        {checkpoint.sessionCount}
      </Text>
      <Text style={[s.cell, s.numCell, { width: COL.files }]} numberOfLines={1}>
        {checkpoint.filesTouched.length}
      </Text>
      <Text style={[s.cell, s.numCell, { width: COL.tokens }]} numberOfLines={1}>
        {outTokens > 0 ? outTokens.toLocaleString() : "—"}
      </Text>
    </TouchableOpacity>
  );
}

// ─── Screen ───────────────────────────────────────────────────────────────────

export function Checkpoints() {
  const router = useRouter();
  const [checkpoints, setCheckpoints] = useState<Checkpoint[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const { height } = useWindowDimensions();
  const headerHeight = useHeaderHeight();
  const contentHeight = height - headerHeight;

  const load = useCallback(async () => {
    try {
      setCheckpoints(await fetchCheckpoints());
      setError(null);
    } catch (err) {
      setError(String(err));
    }
  }, []);

  useEffect(() => {
    load().finally(() => setLoading(false));
    return subscribeToUpdates(() => { load().catch(() => undefined); });
  }, [load]);

  if (loading) {
    return (
      <>
        <Stack.Screen options={{ title: "Checkpoints" }} />
        <View style={s.centered}>
          <ActivityIndicator size="large" color="#6366f1" />
        </View>
      </>
    );
  }

  if (error) {
    return (
      <>
        <Stack.Screen options={{ title: "Checkpoints" }} />
        <View style={s.centered}>
          <Text style={s.errorText}>{error}</Text>
        </View>
      </>
    );
  }

  return (
    <>
      <Stack.Screen
        options={{
          title: "Checkpoints",
          headerRight: () => (
            <TouchableOpacity
              onPress={() => router.push("/checkpoints/timeline")}
              style={{ marginRight: 14 }}
            >
              <Text style={{ fontSize: 15 }}>◎</Text>
            </TouchableOpacity>
          ),
        }}
      />
      <View style={[s.scroll, { height: contentHeight }]}>
        <View style={[s.headerRow, { minWidth: TOTAL_WIDTH }]}>
          {COLUMNS.map(({ label, width }) => (
            <Text key={label} style={[s.headerCell, { width }]}>{label}</Text>
          ))}
        </View>
        <View style={{ minWidth: TOTAL_WIDTH }}>
          {checkpoints.length === 0 ? (
            <View style={s.centered}>
              <Text style={s.emptyText}>No checkpoints indexed yet.</Text>
            </View>
          ) : (
            checkpoints.map((cp) => (
              <CheckpointRow
                key={cp.checkpointId}
                checkpoint={cp}
                onPress={() =>
                  router.push({
                    pathname: "/checkpoints/[checkpointId]",
                    params: {
                      checkpointId: cp.checkpointId,
                      title: cp.branch ? `${cp.branch} · ${cp.checkpointId}` : cp.checkpointId,
                    },
                  })
                }
              />
            ))
          )}
        </View>
      </View>
    </>
  );
}

// ─── Styles ───────────────────────────────────────────────────────────────────

const s = StyleSheet.create({
  scroll: {
    overflow: "scroll",
    minWidth: TOTAL_WIDTH,
    backgroundColor: "#fff",
  },
  centered: {
    alignItems: "center",
    justifyContent: "center",
    padding: 24,
    minHeight: 80,
  },
  headerRow: {
    flexDirection: "row",
    backgroundColor: "#f9fafb",
    borderBottomWidth: 2,
    borderBottomColor: "#e5e7eb",
    paddingVertical: 8,
    paddingHorizontal: 8,
  },
  headerCell: {
    fontSize: 12,
    fontWeight: "700",
    color: "#6b7280",
    paddingHorizontal: 4,
    textTransform: "uppercase",
    letterSpacing: 0.5,
  },
  row: {
    flexDirection: "row",
    alignItems: "center",
    paddingVertical: 8,
    paddingHorizontal: 8,
    borderBottomWidth: 1,
    borderBottomColor: "#e5e7eb",
  },
  cell: {
    paddingHorizontal: 4,
    overflow: "hidden",
  },
  idCell: {
    fontFamily: "monospace",
    fontSize: 13,
    color: "#059669",
    fontWeight: "600",
  },
  cellText: {
    fontSize: 13,
    color: "#374151",
  },
  intentCell: {
    fontSize: 12,
    color: "#6b7280",
    fontStyle: "italic",
  },
  numCell: {
    fontSize: 13,
    color: "#6b7280",
    textAlign: "right",
  },
  errorText: {
    fontSize: 14,
    color: "#ef4444",
    textAlign: "center",
  },
  emptyText: {
    fontSize: 14,
    color: "#9ca3af",
  },
});

import React, { useEffect, useMemo, useState } from "react";
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  useWindowDimensions,
} from "react-native";
import { Stack, useLocalSearchParams } from "expo-router";
import { useHeaderHeight } from "@react-navigation/elements";
import { fetchCheckpoint, fetchCheckpointMessages, type Checkpoint, type CheckpointMessage, type CheckpointSummary } from "../api";
import { CheckpointMessageItem, type ToolResultBlock } from "../components/CheckpointMessageItem";

// ─── Summary card ─────────────────────────────────────────────────────────────

function SummarySection({ label, items }: { label: string; items: string[] }) {
  const [open, setOpen] = useState(false);
  if (items.length === 0) return null;
  return (
    <View style={s.section}>
      <TouchableOpacity onPress={() => setOpen((v) => !v)} style={s.sectionHeader}>
        <Text style={s.sectionLabel}>{label} ({items.length})</Text>
        <Text style={s.sectionChevron}>{open ? "▲" : "▼"}</Text>
      </TouchableOpacity>
      {open && items.map((item, i) => (
        <Text key={i} style={s.sectionItem} selectable>{"· "}{item}</Text>
      ))}
    </View>
  );
}

function CodeLearningSections({ items }: { items: Array<{ path: string; finding: string }> }) {
  const [open, setOpen] = useState(false);
  if (items.length === 0) return null;
  return (
    <View style={s.section}>
      <TouchableOpacity onPress={() => setOpen((v) => !v)} style={s.sectionHeader}>
        <Text style={s.sectionLabel}>Code learnings ({items.length})</Text>
        <Text style={s.sectionChevron}>{open ? "▲" : "▼"}</Text>
      </TouchableOpacity>
      {open && items.map((item, i) => (
        <View key={i} style={s.codeLearningItem}>
          <Text style={s.codePath}>{item.path}</Text>
          <Text style={s.sectionItem} selectable>{item.finding}</Text>
        </View>
      ))}
    </View>
  );
}

function SummaryCard({ summary }: { summary: CheckpointSummary }) {
  return (
    <View style={s.summaryCard}>
      <Text style={s.summaryCardLabel}>Summary</Text>
      <View style={s.summaryBlock}>
        <Text style={s.fieldLabel}>Intent</Text>
        <Text style={s.fieldText} selectable>{summary.intent}</Text>
      </View>
      <View style={s.summaryBlock}>
        <Text style={s.fieldLabel}>Outcome</Text>
        <Text style={s.fieldText} selectable>{summary.outcome}</Text>
      </View>
      <SummarySection label="Repo learnings"     items={summary.repoLearnings} />
      <CodeLearningSections                       items={summary.codeLearnings} />
      <SummarySection label="Workflow learnings"  items={summary.workflowLearnings} />
      <SummarySection label="Friction"            items={summary.friction} />
      <SummarySection label="Open items"          items={summary.openItems} />
    </View>
  );
}

// ─── Screen ───────────────────────────────────────────────────────────────────

export function CheckpointDetail() {
  const { checkpointId, title } = useLocalSearchParams<{ checkpointId: string; title?: string }>();
  const [checkpoint, setCheckpoint] = useState<Checkpoint | null>(null);
  const [messages, setMessages] = useState<CheckpointMessage[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showCompact, setShowCompact] = useState(false);

  const { height } = useWindowDimensions();
  const headerHeight = useHeaderHeight();
  const contentHeight = height - headerHeight;

  useEffect(() => {
    Promise.all([fetchCheckpoint(checkpointId), fetchCheckpointMessages(checkpointId)])
      .then(([cp, msgs]) => { setCheckpoint(cp); setMessages(msgs); setError(null); })
      .catch((err: unknown) => setError(String(err)))
      .finally(() => setLoading(false));
  }, [checkpointId]);

  const toolResults = useMemo(() => {
    const map = new Map<string, ToolResultBlock>();
    for (const msg of messages) {
      if (msg.type !== "user") continue;
      const d = msg.data as Record<string, unknown>;
      const content = (d.message as Record<string, unknown> | undefined)?.content;
      if (!Array.isArray(content)) continue;
      for (const block of content as ToolResultBlock[]) {
        if (block.type === "tool_result" && block.tool_use_id) {
          map.set(block.tool_use_id, block);
        }
      }
    }
    return map;
  }, [messages]);

  const screenTitle = title ?? checkpointId;

  if (loading) {
    return (
      <>
        <Stack.Screen options={{ title: screenTitle }} />
        <View style={s.centered}>
          <ActivityIndicator size="large" color="#059669" />
        </View>
      </>
    );
  }

  if (error) {
    return (
      <>
        <Stack.Screen options={{ title: screenTitle }} />
        <View style={s.centered}>
          <Text style={s.errorText}>{error}</Text>
        </View>
      </>
    );
  }

  const counts = messages.reduce<Record<string, number>>((acc, m) => {
    acc[m.type] = (acc[m.type] ?? 0) + 1;
    return acc;
  }, {});

  return (
    <>
      <Stack.Screen options={{ title: screenTitle }} />
      <View style={[s.scroll, { height: contentHeight }]}>
        <View style={s.statsBar}>
          {Object.entries(counts).map(([type, count]) => (
            <View key={type} style={s.statChip}>
              <Text style={s.statText}>{type} {count}</Text>
            </View>
          ))}
          <TouchableOpacity
            style={[s.filterBtn, showCompact && s.filterBtnActive]}
            onPress={() => setShowCompact((v) => !v)}
          >
            <Text style={[s.filterBtnText, showCompact && s.filterBtnTextActive]}>
              {showCompact ? "▲ hide system" : "▼ show system"}
            </Text>
          </TouchableOpacity>
        </View>

        {checkpoint?.summary && <SummaryCard summary={checkpoint.summary} />}

        {messages.length === 0 ? (
          <View style={s.centered}>
            <Text style={s.emptyText}>No messages in this checkpoint.</Text>
          </View>
        ) : (
          messages.map((msg) => (
            <CheckpointMessageItem
              key={msg.uuid}
              msg={msg}
              toolResults={toolResults}
              showCompact={showCompact}
            />
          ))
        )}
      </View>
    </>
  );
}

// ─── Styles ───────────────────────────────────────────────────────────────────

const s = StyleSheet.create({
  scroll: {
    backgroundColor: "#fff",
    overflow: "scroll",
  },
  centered: {
    alignItems: "center",
    justifyContent: "center",
    padding: 24,
    minHeight: 120,
  },
  statsBar: {
    flexDirection: "row",
    flexWrap: "wrap",
    gap: 6,
    alignItems: "center",
    paddingHorizontal: 12,
    paddingVertical: 8,
    backgroundColor: "#f8fafc",
    borderBottomWidth: 1,
    borderBottomColor: "#e5e7eb",
  },
  statChip: {
    backgroundColor: "#e2e8f0",
    borderRadius: 4,
    paddingHorizontal: 7,
    paddingVertical: 2,
  },
  statText: {
    fontSize: 11,
    color: "#475569",
    fontFamily: "monospace",
  },
  filterBtn: {
    marginLeft: "auto",
    borderRadius: 4,
    paddingHorizontal: 8,
    paddingVertical: 3,
    borderWidth: 1,
    borderColor: "#cbd5e1",
  },
  filterBtnActive: {
    backgroundColor: "#0f172a",
    borderColor: "#0f172a",
  },
  filterBtnText: {
    fontSize: 11,
    color: "#64748b",
  },
  filterBtnTextActive: {
