     1→import React, { useState } from "react";
     2→import { View, Text, TouchableOpacity, StyleSheet } from "react-native";
     3→import type { Event } from "../api";
     4→import { MarkdownView } from "./MarkdownView";
     5→
     6→interface Props {
     7→  event: Event;
     8→}
     9→
    10→// ─── Helpers ──────────────────────────────────────────────────────────────────
    11→
    12→function fmt(iso: string): string {
    13→  const d = new Date(iso);
    14→  return (
    15→    String(d.getHours()).padStart(2, "0") + ":" +
    16→    String(d.getMinutes()).padStart(2, "0") + ":" +
    17→    String(d.getSeconds()).padStart(2, "0")
    18→  );
    19→}
    20→
    21→function str(v: unknown): string {
    22→  return typeof v === "string" ? v : "";
    23→}
    24→
    25→function data(event: Event): Record<string, unknown> {
    26→  return (event.data ?? {}) as Record<string, unknown>;
    27→}
    28→
    29→
    30→// ─── Blocked badge ────────────────────────────────────────────────────────────
    31→
    32→function BlockedBadge() {
    33→  return (
    34→    <View style={s.blockedBadge}>
    35→      <Text style={s.blockedText}>BLOCKED</Text>
    36→    </View>
    37→  );
    38→}
    39→
    40→// ─── UserPromptSubmit card ────────────────────────────────────────────────────
    41→
    42→function UserPromptCard({ event }: { event: Event }) {
    43→  const prompt = str(data(event).prompt);
    44→  return (
    45→    <View style={s.userCard} {...{ title: "User" } as object}>
    46→      <View style={s.userRow}>
    47→        <Text style={s.cardTime}>{fmt(event.timestamp)}</Text>
    48→        <Text style={s.promptText} selectable>{prompt || "(no prompt)"}</Text>
    49→        {event.blocked && <BlockedBadge />}
    50→      </View>
    51→    </View>
    52→  );
    53→}
    54→
    55→// ─── Stop / Assistant card ────────────────────────────────────────────────────
    56→
    57→function AssistantCard({ event }: { event: Event }) {
    58→  const d = data(event);
    59→  const msg = str(d.last_assistant_message);
    60→  const reason = str(d.reason);
    61→  return (
    62→    <View style={s.assistantCard} {...{ title: "Assistant" } as object}>
    63→      <View style={s.cardHeader}>
    64→        {reason ? <Text style={s.reasonBadge}>{reason}</Text> : null}
    65→        <Text style={s.cardTime}>{fmt(event.timestamp)}</Text>
    66→        {event.blocked && <BlockedBadge />}
    67→      </View>
    68→      <MarkdownView text={msg || "(no message)"} />
    69→    </View>
    70→  );
    71→}
    72→
    73→// ─── Notification row ─────────────────────────────────────────────────────────
    74→
    75→const NOTIF_STYLE: Record<string, { color: string; bg: string; sym: string }> = {
    76→  permission_prompt: { color: "#b45309", bg: "#fffbeb", sym: "?" },
    77→  idle_prompt:       { color: "#6b7280", bg: "#f9fafb", sym: "…" },
    78→};
    79→
    80→function NotificationRow({ event }: { event: Event }) {
    81→  const d = data(event);
    82→  const msg = str(d.message);
    83→  const ntype = str(d.notification_type);
    84→  const style = NOTIF_STYLE[ntype] ?? { color: "#6b7280", bg: "#f9fafb", sym: "◆" };
    85→  return (
    86→    <View style={[s.notifRow, { backgroundColor: style.bg }]}>
    87→      <Text style={[s.notifSym, { color: style.color }]}>{style.sym}</Text>
    88→      <Text style={[s.notifMsg, { color: style.color }]}>{msg}</Text>
    89→      <Text style={s.compactTime}>{fmt(event.timestamp)}</Text>
    90→      {event.blocked && <BlockedBadge />}
    91→    </View>
    92→  );
    93→}
    94→
    95→// ─── SessionStart / SessionEnd row ────────────────────────────────────────────
    96→
    97→function SessionRow({ event }: { event: Event }) {
    98→  const d = data(event);
    99→  const isStart = event.event === "SessionStart";
   100→  const color = "#8b5cf6";
   101→  const sym = isStart ? "◉" : "◎";
   102→  const extra = isStart ? str(d.source) : str(d.reason);
   103→  const cwd = str(d.cwd);
   104→  return (
   105→    <View style={s.sessionRow}>
   106→      <Text style={[s.sessionSym, { color }]}>{sym}</Text>
   107→      <View style={s.sessionBody}>
   108→        <Text style={[s.sessionEvent, { color }]}>{event.event}</Text>
   109→        {extra ? <Text style={s.sessionExtra}>{extra}</Text> : null}
   110→        {cwd ? <Text style={s.sessionCwd} numberOfLines={1}>{cwd}</Text> : null}
   111→      </View>
   112→      <Text style={s.compactTime}>{fmt(event.timestamp)}</Text>
   113→      {event.blocked && <BlockedBadge />}
   114→    </View>
   115→  );
   116→}
   117→
   118→// ─── Generic compact row ──────────────────────────────────────────────────────
   119→
   120→const EVENT_SYMBOL: Record<string, string> = {
   121→  SubagentStart: "▷",
   122→  SubagentStop: "◁",
   123→  PreCompact: "⌃",
   124→  Setup: "⚙",
   125→  PermissionRequest: "?",
   126→};
   127→
   128→const EVENT_COLOR: Record<string, string> = {
   129→  SubagentStart: "#06b6d4",
   130→  SubagentStop: "#06b6d4",
   131→  PreCompact: "#94a3b8",
   132→  Setup: "#94a3b8",
   133→  PermissionRequest: "#f59e0b",
   134→};
   135→
   136→function CompactRow({ event }: { event: Event }) {
   137→  const [expanded, setExpanded] = useState(false);
   138→  const sym = EVENT_SYMBOL[event.event] ?? "◆";
   139→  const color = EVENT_COLOR[event.event] ?? "#64748b";
   140→  const d = data(event);
   141→  // Show any interesting text field
   142→  const body = str(d.message) || str(d.reason) || str(d.source);
   143→  const hasBody = body.length > 0;
   144→  return (
   145→    <TouchableOpacity
   146→      onPress={hasBody ? () => setExpanded((v) => !v) : undefined}
   147→      activeOpacity={hasBody ? 0.7 : 1}
   148→      style={s.compactRow}
   149→    >
   150→      <Text style={[s.compactSym, { color }]}>{sym}</Text>
   151→      <Text style={[s.compactEvent, { color }]}>{event.event}</Text>
   152→      <Text style={s.compactTime}>{fmt(event.timestamp)}</Text>
   153→      {event.blocked && <BlockedBadge />}
   154→      {hasBody && <Text style={s.chevron}>{expanded ? "▲" : "▼"}</Text>}
   155→      {expanded && body ? (
   156→        <Text style={s.compactBody}>{body}</Text>
   157→      ) : null}
   158→    </TouchableOpacity>
   159→  );
   160→}
   161→
   162→// ─── Main export ─────────────────────────────────────────────────────────────
   163→
   164→export function EventItem({ event }: Props) {
   165→  if (event.event === "UserPromptSubmit") return <UserPromptCard event={event} />;
   166→  if (event.event === "Stop") return <AssistantCard event={event} />;
   167→  if (event.event === "Notification") return <NotificationRow event={event} />;
   168→  if (event.event === "SessionStart" || event.event === "SessionEnd") return <SessionRow event={event} />;
   169→  return <CompactRow event={event} />;
   170→}
   171→
   172→// ─── Styles ───────────────────────────────────────────────────────────────────
   173→
   174→const s = StyleSheet.create({
   175→  // User card
   176→  userCard: {
   177→    borderLeftWidth: 4,
   178→    borderLeftColor: "#6366f1",
   179→    backgroundColor: "#ddd6fe",
   180→    paddingVertical: 10,
   181→    paddingHorizontal: 14,
   182→  },
   183→  cardHeader: {
   184→    flexDirection: "row",
   185→    alignItems: "center",
   186→    gap: 8,
   187→    marginBottom: 4,
   188→  },
   189→  userRow: {
   190→    flexDirection: "row",
   191→    alignItems: "baseline",
   192→    gap: 8,
   193→  },
   194→  cardTime: {
   195→    fontSize: 11,
   196→    color: "#9ca3af",
   197→    flexShrink: 0,
   198→  },
   199→  promptText: {
   200→    fontFamily: "monospace",
   201→    fontSize: 12,
   202→    color: "#1e1b4b",
   203→    lineHeight: 18,
   204→    flex: 1,
   205→  },
   206→
   207→  // Assistant card
   208→  assistantCard: {
   209→    borderLeftWidth: 4,
   210→    borderLeftColor: "#f59e0b",
   211→    backgroundColor: "#fff",
   212→    paddingVertical: 10,
   213→    paddingHorizontal: 14,
   214→  },
   215→  reasonBadge: {
   216→    fontSize: 10,
   217→    color: "#92400e",
   218→    backgroundColor: "#fde68a",
   219→    paddingHorizontal: 5,
   220→    paddingVertical: 1,
   221→    borderRadius: 3,
   222→  },
   223→  emptyMsg: {
   224→    fontSize: 13,
   225→    color: "#9ca3af",
   226→    fontStyle: "italic",
   227→  },
   228→
   229→  // Notification
   230→  notifRow: {
   231→    flexDirection: "row",
   232→    alignItems: "center",
   233→    gap: 8,
   234→    paddingVertical: 5,
   235→    paddingHorizontal: 12,
   236→    borderBottomWidth: 1,
   237→    borderBottomColor: "#f1f5f9",
   238→  },
   239→  notifSym: {
   240→    fontSize: 13,
   241→    fontWeight: "700",
   242→    width: 16,
   243→    textAlign: "center",
   244→  },
   245→  notifMsg: {
   246→    fontSize: 12,
   247→    flex: 1,
   248→  },
   249→
   250→  // Session
