     2→import { View, Text, TouchableOpacity, StyleSheet } from "react-native";
     3→import type { Event } from "../api";
     4→
     5→interface Props {
     6→  pre: Event;
     7→  post?: Event; // undefined = still pending
     8→  failed: boolean;
     9→}
    10→
    11→// ─── Helpers ──────────────────────────────────────────────────────────────────
    12→
    13→function fmt(iso: string): string {
    14→  const d = new Date(iso);
    15→  return (
    16→    String(d.getHours()).padStart(2, "0") + ":" +
    17→    String(d.getMinutes()).padStart(2, "0") + ":" +
    18→    String(d.getSeconds()).padStart(2, "0")
    19→  );
    20→}
    21→
    22→function str(v: unknown): string {
    23→  return typeof v === "string" ? v : "";
    24→}
    25→
    26→function toolHint(toolName: string, data: unknown): string {
    27→  if (!data || typeof data !== "object") return "";
    28→  const inp = (data as Record<string, unknown>).tool_input;
    29→  if (!inp || typeof inp !== "object") return "";
    30→  const i = inp as Record<string, unknown>;
    31→  const s = (k: string) => (typeof i[k] === "string" ? String(i[k]) : undefined);
    32→  switch (toolName) {
    33→    case "Read":
    34→    case "Write":
    35→    case "Edit":      return s("file_path") ?? "";
    36→    case "Bash":      return (s("command") ?? "").replace(/\s+/g, " ").slice(0, 80);
    37→    case "Glob":      return s("pattern") ?? "";
    38→    case "Grep":      return s("pattern") ?? "";
    39→    case "WebFetch":  return s("url") ?? "";
    40→    case "WebSearch": return s("query") ?? "";
    41→    default:          return "";
    42→  }
    43→}
    44→
    45→function truncated(val: unknown, max = 1200): string | undefined {
    46→  if (val === undefined) return undefined;
    47→  const s = typeof val === "string" ? val : JSON.stringify(val, null, 2);
    48→  return s.length > max ? s.slice(0, max) + "\n…" : s;
    49→}
    50→
    51→// ─── Diff view for Edit tool ──────────────────────────────────────────────────
    52→
    53→function DiffView({ oldStr, newStr }: { oldStr: string; newStr: string }) {
    54→  return (
    55→    <View style={ts.diffWrap}>
    56→      {oldStr ? (
    57→        <View style={ts.diffDel}>
    58→          <Text style={ts.diffText} selectable>
    59→            {oldStr.split("\n").map((l) => "− " + l).join("\n")}
    60→          </Text>
    61→        </View>
    62→      ) : null}
