     4→// ─── Inline types ─────────────────────────────────────────────────────────────
     5→
     6→type InlineNode =
     7→  | { t: "text"; s: string }
     8→  | { t: "bold"; s: string }
     9→  | { t: "italic"; s: string }
    10→  | { t: "code"; s: string };
    11→
    12→function parseInline(raw: string): InlineNode[] {
    13→  const nodes: InlineNode[] = [];
    14→  // Match **bold**, *italic*, ``double-backtick code``, `code` — in priority order
    15→  const re = /(\*\*(?:[^*]|\*(?!\*))+?\*\*|\*(?:[^*\n])+?\*|``(?:[^`]|`(?!`))+``|`[^`\n]+?`)/g;
    16→  let last = 0;
    17→  let m: RegExpExecArray | null;
    18→  while ((m = re.exec(raw)) !== null) {
    19→    if (m.index > last) nodes.push({ t: "text", s: raw.slice(last, m.index) });
    20→    const tok = m[1];
    21→    if (tok.startsWith("**")) nodes.push({ t: "bold", s: tok.slice(2, -2) });
    22→    else if (tok.startsWith("``")) nodes.push({ t: "code", s: tok.slice(2, -2).trim() });
    23→    else if (tok.startsWith("`")) nodes.push({ t: "code", s: tok.slice(1, -1) });
    24→    else nodes.push({ t: "italic", s: tok.slice(1, -1) });
    25→    last = m.index + tok.length;
    26→  }
    27→  if (last < raw.length) nodes.push({ t: "text", s: raw.slice(last) });
    28→  return nodes;
    29→}
    30→
    31→// ─── Block types ─────────────────────────────────────────────────────────────
    32→
    33→type Block =
    34→  | { kind: "code"; lang: string; code: string }
    35→  | { kind: "h"; level: 1 | 2 | 3; inline: InlineNode[] }
    36→  | { kind: "bullets"; items: InlineNode[][] }
    37→  | { kind: "numbered"; items: InlineNode[][] }
    38→  | { kind: "hr" }
    39→  | { kind: "table"; headers: InlineNode[][]; rows: InlineNode[][][] }
    40→  | { kind: "para"; inline: InlineNode[] };
    41→
    42→function parseBlocks(md: string): Block[] {
    43→  const lines = md.split("\n");
    44→  const out: Block[] = [];
    45→  let i = 0;
    46→
    47→  while (i < lines.length) {
    48→    const line = lines[i];
    49→
    50→    // Fenced code block (``` or ~~~), with optional leading whitespace
    51→    const trimmedLine = line.trimStart();
    52→    if (trimmedLine.startsWith("```") || trimmedLine.startsWith("~~~")) {
    53→      const fence = trimmedLine.slice(0, 3);
    54→      const lang = trimmedLine.slice(3).trim();
    55→      const codeLines: string[] = [];
