          const fs = block.level === 1 ? 16 : block.level === 2 ? 14 : 13;
          return <Tag key={idx} style={{ fontSize: fs, fontWeight: 700, color: "#111827", margin: "10px 0 4px" }}><Inline nodes={block.inline} /></Tag>;
        }
        if (block.kind === "hr") {
