    10→// ─── Response types ───────────────────────────────────────────────────────────
    11→
    12→interface SessionResponse {
    13→  sessionId: string;
    14→  startedAt: string;
    15→  updatedAt: string;
    16→  cwd: string;
    17→  repoRoot: string | null;
    18→  repoName: string | null;
    19→  parentSessionId: string | null;
    20→  childSessionIds: string[];
    21→  gitUserName: string | null;
    22→  gitUserEmail: string | null;
    23→  prompt: string | null;
    24→  summary: string | null;
    25→  keywords: string[];
    26→}
    27→
    28→interface EventResponse {
    29→  id: number;
    30→  timestamp: string;
    31→  event: string;
    32→  sessionId: string;
    33→  blocked: boolean;
    34→  data: unknown;
    35→  summary: string | null;
    36→  keywords: string[];
    37→}
    38→
    39→interface OverviewResponse {
    40→  sessionId: string;
    41→  summary: string;
    42→  keywords: string[];
    43→  startedAt: string;
    44→  endedAt: string;
    45→}
    46→
    47→// ─── Mapping helpers ──────────────────────────────────────────────────────────
    48→
    49→function mapSummary(s: {
    50→  intent: string;
    51→  outcome: string;
    52→  learningsRepo: string | null;
    53→  learningsCode: string | null;
    54→  learningsWorkflow: string | null;
    55→  friction: string | null;
    56→  openItems: string | null;
    57→}) {
    58→  return {
    59→    intent: s.intent,
    60→    outcome: s.outcome,
    61→    repoLearnings:     s.learningsRepo     ? (JSON.parse(s.learningsRepo)     as string[]) : [],
    62→    codeLearnings:     s.learningsCode     ? (JSON.parse(s.learningsCode)     as Array<{ path: string; finding: string }>) : [],
    63→    workflowLearnings: s.learningsWorkflow ? (JSON.parse(s.learningsWorkflow) as string[]) : [],
    64→    friction:          s.friction          ? (JSON.parse(s.friction)          as string[]) : [],
    65→    openItems:         s.openItems         ? (JSON.parse(s.openItems)         as string[]) : [],
    66→  };
    67→}
    68→
    69→
    70→function mapSession(
    71→  s: {
    72→    sessionId: string;
    73→    startedAt: Date;
    74→    updatedAt: Date;
    75→    cwd: string;
    76→    repoRoot: string | null;
    77→    repoName: string | null;
    78→    parentSessionId: string | null;
    79→    gitUserName: string | null;
    80→    gitUserEmail: string | null;
    81→    prompt: string | null;
    82→    summary: string | null;
    83→    keywords: string | null;
    84→  },
    85→  childSessionIds: string[] = [],
    86→): SessionResponse {
    87→  return {
    88→    sessionId: s.sessionId,
    89→    startedAt: s.startedAt.toISOString(),
    90→    updatedAt: s.updatedAt.toISOString(),
    91→    cwd: s.cwd,
    92→    repoRoot: s.repoRoot,
    93→    repoName: s.repoName,
    94→    parentSessionId: s.parentSessionId,
    95→    childSessionIds,
    96→    gitUserName: s.gitUserName,
    97→    gitUserEmail: s.gitUserEmail,
    98→    prompt: s.prompt,
    99→    summary: s.summary,
   100→    keywords: s.keywords ? (JSON.parse(s.keywords) as string[]) : [],
   101→  };
   102→}
   103→
   104→function mapEvent(e: {
   105→  id: number;
   106→  timestamp: Date;
   107→  event: string;
   108→  sessionId: string;
   109→  blocked: boolean;
   110→  data: string;
   111→  summary: string | null;
   112→  keywords: string | null;
   113→}): EventResponse {
   114→  let parsedData: unknown;
   115→  try {
   116→    parsedData = JSON.parse(e.data);
   117→  } catch {
   118→    parsedData = e.data;
   119→  }
   120→  return {
   121→    id: e.id,
   122→    timestamp: e.timestamp.toISOString(),
   123→    event: e.event,
   124→    sessionId: e.sessionId,
   125→    blocked: e.blocked,
   126→    data: parsedData,
   127→    summary: e.summary,
   128→    keywords: e.keywords ? (JSON.parse(e.keywords) as string[]) : [],
   129→  };
   130→}
