   144→      const sessions = await db.session.findMany({
   145→        orderBy: { updatedAt: "desc" },
   146→      });
   147→      // Build parent → children map in memory (no extra queries)
   148→      const childMap = new Map<string, string[]>();
   149→      for (const s of sessions) {
   150→        if (s.parentSessionId) {
   151→          const arr = childMap.get(s.parentSessionId) ?? [];
