   359→  type V2Session = {
   360→    summary: {
   361→      intent: string; outcome: string;
   362→      openItems: { text: string }[];
   363→      frictionItems: { text: string }[];
   364→      repoLearnings: { text: string }[];
   365→      codeLearnings: { path: string; finding: string }[];
   366→      workflowLearnings: { text: string }[];
   367→    } | null;
   368→  };
   369→
   370→  function mapV2Summary(summary: NonNullable<V2Session["summary"]>) {
   371→    return {
   372→      intent:            summary.intent,
   373→      outcome:           summary.outcome,
   374→      openItems:         summary.openItems.map((r) => r.text),
   375→      friction:          summary.frictionItems.map((r) => r.text),
   376→      repoLearnings:     summary.repoLearnings.map((r) => r.text),
   377→      codeLearnings:     summary.codeLearnings.map((r) => ({ path: r.path, finding: r.finding })),
   378→      workflowLearnings: summary.workflowLearnings.map((r) => r.text),
   379→    };
   380→  }
   381→
   382→  const V2_SESSION_INCLUDE = {
   383→    summary: {
   384→      include: {
   385→        openItems:         true,
   386→        frictionItems:     true,
   387→        repoLearnings:     true,
   388→        codeLearnings:     true,
   389→        workflowLearnings: true,
   390→      },
   391→    },
   392→  } as const;
   393→
   394→  const V2_SESSION_ORDER = { createdAt: "desc" as const };
