   408→      const sessions = await db.checkpointSessionMetadata.findMany({
   409→        where:   { checkpointId: { in: checkpointIds } },
   410→        orderBy: V2_SESSION_ORDER,
   411→        include: V2_SESSION_INCLUDE,
   412→      });
   413→
   414→      // Group sessions by checkpointId
   415→      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   416→      for (const s of sessions) {
   417→        const arr = sessionsByCheckpoint.get(s.checkpointId) ?? [];
   418→        arr.push(s);
   419→        sessionsByCheckpoint.set(s.checkpointId, arr);
   420→      }
   421→
   422→      res.json(checkpoints.map((c) => {
   423→        const cpSessions = sessionsByCheckpoint.get(c.checkpointId) ?? [];
   424→        const summary = cpSessions.find((s) => s.summary)?.summary ?? null;
