   432→          tokenUsage: c.tokenUsage ? {
   433→            inputTokens:         c.tokenUsage.inputTokens,
   434→            cacheCreationTokens: c.tokenUsage.cacheCreationTokens,
   435→            cacheReadTokens:     c.tokenUsage.cacheReadTokens,
   436→            outputTokens:        c.tokenUsage.outputTokens,
   437→            apiCallCount:        c.tokenUsage.apiCallCount,
   438→          } : null,
   439→          filesTouched:  c.filesTouched.map((f) => f.filePath.path),
   440→          sessionCount:  cpSessions.length,
   441→          summary: summary ? mapV2Summary(summary) : null,
   442→        };
   443→      }));
   444→    } catch (err) {
