   526→
   527→  // Create HTTP server and attach WebSocket server (shared port)
   528→  const httpServer = createServer(app);
   529→  const wss = new WebSocketServer({ server: httpServer });
   530→
   531→  // WebSocket change detection — poll every 2s, broadcast on new events
   532→  let lastMaxId: number | null = null;
   533→  const poller = setInterval(async () => {
   534→    try {
   535→      const latest = await db.event.findFirst({
   536→        orderBy: { id: "desc" },
   537→        select: { id: true },
   538→      });
   539→      const currentId = latest?.id ?? null;
   540→      if (currentId !== lastMaxId) {
   541→        lastMaxId = currentId;
   542→        const message = JSON.stringify({ type: "sessions_updated" });
   543→        for (const client of wss.clients) {
   544→          if (client.readyState === WebSocket.OPEN) {
   545→            client.send(message);
   546→          }
   547→        }
   548→      }
   549→    } catch {
   550→      // Non-fatal polling error — keep running
   551→    }
   552→  }, 2000);
   553→
   554→  // ── Checkpoint auto-indexer ───────────────────────────────────────────────
   555→
   556→  const WORKTREE_PATH = "/tmp/gossamer-checkpoints";
   557→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   558→  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   559→
   560→  if (repoDir) {
   561→    // Ensure worktree exists (reuse across restarts)
   562→    if (!existsSync(WORKTREE_PATH)) {
   563→      try {
   564→        execSync(
   565→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   566→          { stdio: "pipe" },
   567→        );
   568→        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   569→      } catch (err) {
   570→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
